import{_ as i,g as s,h as r,S as a}from"./chunks/vitepress-theme-teek.B9ybUUp0.js";const d=JSON.parse('{"title":"走出“目标隧道”：用系统与数学思维重构底层逻辑","description":"摘要总结：书接上文《向内思变》，本文记录了笔者在后疫情时代从“闭关”走向“向外体验”的尝试与心得。面对机械执行带来的“目标隧道”效应，笔者尝试跳出单一的线性规划，转而寻求更底层的认知逻辑。文章通过重读《要事第一》建立平衡观，利用系统思维（增强/调节回路）构建洞察力，并重新拾起数学思维（概率、稀疏性、多样性）与 AI 视角。这是一次关于如何用科学模型替代机械执行，从本质上重构个人认知体系的深度复盘。","frontmatter":{"date":"2024-01-15T22:16:00.000Z","title":"走出“目标隧道”：用系统与数学思维重构底层逻辑","description":"摘要总结：书接上文《向内思变》，本文记录了笔者在后疫情时代从“闭关”走向“向外体验”的尝试与心得。面对机械执行带来的“目标隧道”效应，笔者尝试跳出单一的线性规划，转而寻求更底层的认知逻辑。文章通过重读《要事第一》建立平衡观，利用系统思维（增强/调节回路）构建洞察力，并重新拾起数学思维（概率、稀疏性、多样性）与 AI 视角。这是一次关于如何用科学模型替代机械执行，从本质上重构个人认知体系的深度复盘。","permalink":"/growth/outer-experience","coverImg":"https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/outer_experience_bg.png","sticky":1,"top":true,"tags":["系统思维","数学思维","模型思维","AI","疫情"],"categories":["个人成长"]},"headers":[],"relativePath":"40.关于/30.成长随笔/01.走出“目标隧道”：用系统与数学思维重构底层逻辑.md","filePath":"40.关于/30.成长随笔/01.走出“目标隧道”：用系统与数学思维重构底层逻辑.md"}'),o={name:"40.关于/30.成长随笔/01.走出“目标隧道”：用系统与数学思维重构底层逻辑.md"};function e(n,t,p,l,g,h){return r(),s("div",null,[...t[0]||(t[0]=[a('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /40.关于/30.成长随笔/01.走出“目标隧道”：用系统与数学思维重构底层逻辑.md for this page in Markdown format</div><h1 id="走出-目标隧道-用系统与数学思维重构底层逻辑" tabindex="-1">走出“目标隧道”：用系统与数学思维重构底层逻辑 <a class="header-anchor" href="#走出-目标隧道-用系统与数学思维重构底层逻辑" aria-label="Permalink to “走出“目标隧道”：用系统与数学思维重构底层逻辑”">​</a></h1><blockquote><p><strong>摘要总结：</strong>书接上文《向内思变》，本文记录了笔者在后疫情时代从“闭关”走向“向外体验”的尝试与心得。面对机械执行带来的“目标隧道”效应，笔者尝试跳出单一的线性规划，转而寻求更底层的认知逻辑。文章通过重读《要事第一》建立平衡观，利用<strong>系统思维（增强/调节回路）构建洞察力，并重新拾起数学思维（概率、稀疏性、多样性）</strong>与 AI 视角。这是一次关于如何用科学模型替代机械执行，从本质上重构个人认知体系的深度复盘。</p></blockquote><h2 id="_1-写在前面" tabindex="-1">1. 写在前面 <a class="header-anchor" href="#_1-写在前面" aria-label="Permalink to “1. 写在前面”">​</a></h2><p>时光荏苒，疫情已经由放开状态继续演变为过去式状态，我们人类也从『闭关』走向了『自由』的社会生活状态。笔者作为社会中的普通一员，自然也不离外，在 2023 年初洋洋洒洒写了一篇在健康、读书与学习、时间管理和混合工作制几个方面的实践与理解（<a href="/growth/inner-experience">向内思变：当疫情给世界按下暂停键，去重构生活秩序</a>），就开开心心地向前看，学着向外体验了。</p><p>那么问题来了，相比之前写出长文，笔者又是近一年没有向外输出软文了。因此，书接上文，本次继续新增一篇中短文，漫谈一下疫情后的向外体验。</p><p>在倒逼自己关注身体健康和时间管理后，虽然在体重和效率两个方面有一定的正向效果，但笔者在连续坚持落地拆解出来的目标过程中，有时会觉得很累。自 OpenAI 这家公司名声大噪且 LLM（大语言模型）被各行各业的人们知晓后，笔者开始质疑起了『目标』，尤其在看过 OpenAI 研究员写的《为什么伟大不能被计划》且向一些大佬咨询请教后，更觉得目标是一把双刃剑：</p><ul><li>对于没有养成良好习惯的人来说，构建切实可行的目标，一旦严格执行落地，在时间的累加效应加持下，大概率是能取得预期结果的。</li><li>对于想要<strong>产出一些创造力或超预期效果的人来讲，目标或许弊大于利</strong>。从笔者的实践来看，<strong>很容易进入『目标隧道』去卷，更容易错过、洞察更优路径的时机（主要还是社会变化过快，打工人太忙）</strong>。</li></ul><p>在目标制定、执行和调整之外，或许存在更通用的方法论，它既包括一些成长书中所谓的使命感，也包括个人智慧与经验等因素。因此，笔者在看书、学习数学基础知识与思维、卷 AI 大模型的过程中，尝试去寻找答案，大概率找不到最好答案，但或多或少能找出优于当前状态的路径或答案。</p><h2 id="_2-重读《要事第一》" tabindex="-1">2. 重读《要事第一》 <a class="header-anchor" href="#_2-重读《要事第一》" aria-label="Permalink to “2. 重读《要事第一》”">​</a></h2><div style="display:flex;justify-content:space-between;align-items:flex-start;"><div style="width:49%;text-align:center;"><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/pic8.png" alt="原则、使命与角色示意树" style="width:100%;border-radius:8px;"><p style="font-size:14px;color:#666;margin-top:8px;">图1：原则、使命与角色示意树</p></div><div style="width:49%;text-align:center;"><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/pic9.png" alt="四个维度圈示意图" style="width:100%;border-radius:8px;"><p style="font-size:14px;color:#666;margin-top:8px;">图2：四个维度圈示意图</p></div></div><p>在重读《要事第一》后，笔者貌似找到了一部分答案。我们经常听到 &quot;人要独立，要有自己的想法&quot;，但<strong>我们确实生活在一个相互依赖的社会，独立与相互依赖这两个看似矛盾的点是我们需要学着平衡的</strong>：</p><ul><li><strong>生活质量本质上取决于相互依赖</strong>，我们的角色是相互依赖的，几乎每个角色实际上都至少通过另外某一个人发生人际关系；</li><li><strong>独立本身并不是目的，真正的独立出现在行之有效的相互依赖之前，同时使我们自己为行之有效的相互依赖做好准备。</strong>也就是说：独立是一个人值得信赖，并且使信赖成为可能。</li><li><strong>平衡思维</strong>是我们的必修课，我们<strong>在不同中长期时间段需要针对自身拆解出几个重要因素，然后借助平衡思维制定合理的多目标去多方面推动</strong>。按照<strong>这种方式，在一定程度上是可以避免进入『目标隧道』的，即使进入了隧道，也不会有大的损失和挫败</strong>，平衡思维下的多维度视角和互相依赖的社会特征会给我们一些启发来调整的。</li><li>在平衡思维下，<strong>目标之上还有原则、使命和角色</strong>这三样东西：<strong>原则让我们尊重客观规律，使命让我们按照自己的心意，角色让我们关注身体、社会/情感、智力、精神、自我更新等多个方面</strong>。</li></ul><p>在平衡思维与多维度视角的基础上，我们很自然地产出长（比如年）、中（比如季度）、短（比如周）三个方面的方向或目标，而不是把自己变成一个工具或发条去卷。自然也能尝试使用《要事第一》作者推出的第四代时间管理模式：<strong>更看重『人』的范畴，所关注的焦点超越了如何对事务进行有效而机械的管理，更重视同别人进行有效的互动合作。以人为本的模式对于在家庭、组织和其他形式的团体中获得成功都是至关重要的</strong>。</p><p>鉴于笔者个人的视角也有一定的局限性，对这部分答案感兴趣的读者，可以去阅读原著，来帮助找出一些适合自己实践的答案。</p><h2 id="_3-基于系统与模型思维构建洞察力模型" tabindex="-1">3. 基于系统与模型思维构建洞察力模型 <a class="header-anchor" href="#_3-基于系统与模型思维构建洞察力模型" aria-label="Permalink to “3. 基于系统与模型思维构建洞察力模型”">​</a></h2><p>众所周知，在数字化时代，我们每天都在与各种各样的系统交互，<strong>每一个表象背后都有一个黑盒子，黑盒子才是规律产生的原因，这个黑盒子也就是系统。</strong></p><p>当系统运转正常的时候，我们在遵循着表象的规律做事，可一旦系统出了问题，这些规律将会失效。如果我们无法洞察表象背后的系统，就不可能知道问题出在哪里，更不知道如何解决。笔者在年轻时也不晓得这个道理，所以经常会固执坚守错误的认知，此后被社会打磨得多了，也就开始琢磨系统运行原理、锻炼自己的洞察力了。</p><p>洞察力模型就是：<strong>理解『表象』背后的『黑盒子』——系统，从而真正从本质上解决问题</strong>。在现实世界中，遇到问题，可以尝试摸索，但不要停留在一些似是而非的概念世界里。在知识付费时代，人们更容易陷入概念世界的迷障，我们应该继续尝试走进科学、知识的世界，甚至是智慧世界来抽象分析，然后结合实际情况降维打击具象世界（疫情期间从 B 站林超所长视频中学到的总结，有兴趣的可自己看原创视频）：</p><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/pic10.png" alt="系统与模型思维构建洞察力模型" style="width:100%;border-radius:8px;margin-bottom:20px;"><p>系统是一组相互关联的要素，即：<strong>系统 = 要素 x 连接关系</strong>。在日常工作与生活中，<strong>要素是易识别，要素的关联关系容易被忽略，但问题的解决方案，常常就藏在这些『连接关系』里</strong>。</p><p>因此，我们可基于拆解与关联的思路按照以下步骤进行：</p><p><strong>1. 寻找因果关系，</strong>人与事、人与物、人与人之间均是如此。若洞察不了关联、因果关系，就一个字『乱』，信息熵越来越大，噪声信息越来越多。因此，我们<strong>可以不断拿起两个可能有关系的变量，问自己：他们之间有增强关系吗，有减弱关系吗？</strong></p><p><strong>2. 寻找增强回路</strong>，因果关系只是单向线段，有头有尾，作用效果从头传到尾就结束了。因此，<strong>我们需要继续思考是否能把结尾与开头也用一条线段连接起来形成一个增强回路</strong>。生活中有很多增强回路的示例：</p><ul><li>人越是积累了知识，积累新知识的能力就越强；积累新知识的能力越强，然后就更能理解新知识.</li><li>人越有信用，别人越愿意和你合作。别人越愿意和你合作，你就能积累更多的信用，就越有人和你合作，如此不断增强；</li></ul><p><strong>3. 很多时候，我们的改善并不需要一直猛踩油门，有时只要松开刹车就好</strong>，在增强回路的成效越来越低时，很难再有突破，调节回路有助于改善增强回路带来的问题。</p><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/pic11.png" alt="三个回路示意图" style="width:100%;border-radius:8px;margin-bottom:20px;"><h3 id="_3-1-增强回路小例子-🌰" tabindex="-1">3.1. 增强回路小例子 🌰 <a class="header-anchor" href="#_3-1-增强回路小例子-🌰" aria-label="Permalink to “3.1. 增强回路小例子 🌰”">​</a></h3><blockquote><p>长久以来，人们给增强回路导致的大起大落现象，起了无数的名字，常见的有：马太效应、经济学家口中的赢家通吃、金融学中的复利效应、互联网公司的指数型增长。</p></blockquote><p><strong>小事情推动靠聪明才智，比较长远的事情要靠建立正向的增强回路</strong>。2022 年底到2023 年末，大模型相当火爆，其背后的 OpenAI 更是成为影响力很大的公司，我们可有关注他们在内部协作的增强回路呢？</p><p>OpenAI 产品推动的思路是： The model is the product，将模型的新功能融入产品，在设计产品过程中与研究团队专注设计模型行为：</p><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/pic12.png" alt="OpenAI 产品推动的思路" style="width:100%;border-radius:8px;margin-bottom:20px;"><p>笔者是一个比较喜欢阅读的人，随着阅读时间的累加，也在逐步思考<strong>怎么才能将自己获得的『输入信息』变成有一定质量与正向效果的『输出』？</strong></p><p>起初，只想到了一些常用的 Push 方法：多读书，多与别人沟通、请教，然后尝试去改善『输出』。</p><p>后来，也不知哪天突发奇想，想起了大学老师曾经在某节课堂上（幸亏当时没有在课上睡觉）提到的一个常见的商业管理模式：<strong>推拉模式（Push/Pull）</strong>。于是就<strong>将『输入』与『输出』简化为：听、说、读、写这四个因素，从 Push 与 Pull 两个方面来编排这四个因素，就能组成输入与输出之间的增强回路</strong>：</p><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/pic13.png" alt="推拉模式" style="width:100%;border-radius:8px;margin-bottom:20px;"><ul><li>所谓 Push，就是继续保持之前的习惯：多听、多读、多思考。</li><li>所谓 Pull，就是强调『输出』，多说、多写、多强调产出。</li></ul><p>让两者形成一个增强回路，变成一个自动运行的卷动机，效果就会比单独 Push 或 Pull 更好。</p><h3 id="_3-2-调节回路" tabindex="-1">3.2. 调节回路 <a class="header-anchor" href="#_3-2-调节回路" aria-label="Permalink to “3.2. 调节回路”">​</a></h3><p>如果说增强回路的存在，是让这个世界走向极端，那么<strong>调节回路的存在，就是让这个世界回归平衡</strong>。<strong>因为增强回路就是『狂卷』，追求极端，很容易陷入『目标隧道』，而调节回路，让人回归平衡、自然，在得到休息的同时增添乐趣</strong>。</p><p>因此，我们在找到自己的增强回路后也需要借助调节回路，以及上述提到的平衡思维来落地调节回路，笔者这里就不做过多赘述。</p><p>当然，<strong>模型思维固然能帮助我们很好地实践，让自己变得简洁、清晰、透彻，但也有其局限性</strong>。在模型基本确定的情况下，其能力的『天花板』也随之确定，天花板的突破需要我们根据实际情况来持续丰富、升级自己的心智模型。</p><h2 id="_4-重读数学的乐趣" tabindex="-1">4. 重读数学的乐趣 <a class="header-anchor" href="#_4-重读数学的乐趣" aria-label="Permalink to “4. 重读数学的乐趣”">​</a></h2><div class="note custom-block"><p class="title note-title custom-block-title">NOTE</p><p>行文至此，基本到了最后一个专题：数学。鉴于许多人对数学有着又爱又恨的恐惧心理，<strong>笔者在这里保证不会引入一些复杂的公式，而是重在强调数学思维真的又底层又有用，更贴近人们常说的『第一性原理』</strong>。</p></div><h3 id="_4-1-怎么突然又学起数学了" tabindex="-1">4.1. 怎么突然又学起数学了？ <a class="header-anchor" href="#_4-1-怎么突然又学起数学了" aria-label="Permalink to “4.1. 怎么突然又学起数学了？”">​</a></h3><p>相信很多人都听说过分解、分类、排列、组合、四象限、流程等比较热门的词语，那么问题来了，我们是否梳理总结过自己真正实践、应用了多少呢？笔者还真的刻意梳理过：</p><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/pic14.png" alt="组合示意图" style="width:100%;border-radius:8px;margin-bottom:20px;"><p>在基础逻辑与行动指导、产出表述与写作训练阶段，只要肯花时间去学习领悟，并刻意训练，我们基本都能获得不错的效果。随着时间的积累，笔者逐渐发现自己在底层原理方面的抽象理解能力不是一般的薄弱：</p><ul><li>在函数、复利、排列组合方面也尚可，但很难将决策树、贝叶斯等概率理论应用到日常工作与生活中，后来笔者也观察到身边大部分人也是没能将这些理论应用到实际工作中。</li><li>随着对模型思维、量化分析等兴趣的加强，以及 AI 大模型兴起（成为了 ChatGPT 靠前一批的注册者），数学方面的短板更是凸显。</li></ul><p>因此，基于多方面遇到的问题，笔者就重新学起了数学：</p><ul><li>起初会看一些数学发展史、数学家的故事、日常工作与生活中常用的数学知识。</li><li>在 2023 年更是启动了数学通识基础知识、概率论等基础知识的学习与理解。在大模型越来越被大家熟知后，更在数学基础知识的基础上侧重补充了一些机器学习、神经网络等模型与算法依赖的数学知识（这些知识在大学阶段虽然也学过，但毕业走向工作岗位后，很少有机会将其应用到实际工作中）。</li></ul><h3 id="_4-2-重新发现了有趣的数学思维" tabindex="-1">4.2. 重新发现了有趣的数学思维 <a class="header-anchor" href="#_4-2-重新发现了有趣的数学思维" aria-label="Permalink to “4.2. 重新发现了有趣的数学思维”">​</a></h3><h4 id="分解与分类、排列与组合" tabindex="-1">分解与分类、排列与组合 <a class="header-anchor" href="#分解与分类、排列与组合" aria-label="Permalink to “分解与分类、排列与组合”">​</a></h4><p>相信不少人已经比较熟悉『化繁为简』，『见缝插针』式事务管理。笔者这里依旧把『分解与分类、排列与组合』放在第一位，<strong>我们在接收九年义务教育时就开始学习这些，但很少有人能用这些比较简单的数学思维管理自己的时间与事务</strong>。</p><p>笔者这里只提一个人：雷军，刨除后来的光环不讲，他当年在武汉大学读书时真的将这些应用得淋漓尽致，后来也在不少场合以经历回顾的方式传授给很多年轻人（感兴趣的可在网上搜一些更详细的资料）。所以，笔者也认为：<strong>一个人越早学会将『分解与分类、排列与组合』应用到工作与生活中越好，带来的正向效果特别多，活得不糊里糊涂，有自己的节奏感</strong>。</p><h4 id="多样性红利" tabindex="-1">多样性红利 <a class="header-anchor" href="#多样性红利" aria-label="Permalink to “多样性红利”">​</a></h4><p>假设一个方程代表从一个角度观察得到的结果，那么，如果我们从多个角度观察，就会得到方程组，求解方程组的过程就是整合多个角度的观察结果，找到最接近真相的答案：</p><div style="display:flex;justify-content:space-between;align-items:flex-start;"><div style="width:49%;text-align:center;"><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/pic15.png" alt="病态方程组示意" style="width:100%;border-radius:8px;"><p style="font-size:14px;color:#666;margin-top:8px;">图1：病态方程组：两条线特征近似，稍微发生变化就带来较大误差</p></div><div style="width:49%;text-align:center;"><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/pic16.png" alt="兼顾多样性的方程组示意" style="width:100%;border-radius:8px;"><p style="font-size:14px;color:#666;margin-top:8px;">图2：兼顾多样性的方程组</p></div></div><p>如果我们总是基于斜率非常接近的直线建立方程组，某条直线只要稍微变化一点，最终的答案就会有很大变化。<strong>通过病态方程组，我们可以更好地看清为什么多样性特别重要，多样性已经是一个公认的优势，任何人都会有认知盲点，站在不同角度的人在一起讨论后达成的共识往往最接近真相</strong>。</p><p>因此，我们在日常工作生活中要<strong>试着平衡，运用多样性红利，不应该『过卷、过拟合』，否则容易导致适应性下降，碰到新环境就会各种不适应</strong>。</p><h4 id="这个世界是稀疏的" tabindex="-1">这个世界是稀疏的 <a class="header-anchor" href="#这个世界是稀疏的" aria-label="Permalink to “这个世界是稀疏的”">​</a></h4><p>傅立叶在 1807 年提交了一篇论文，阐述了一个结论：任何一个连续的周期信号，都可以通过不同频率的正弦波叠加得出，<strong>这些正弦波前面的系数大部分为零，只有少部分系数描述了曲线的核心特征</strong>：</p><div style="display:flex;justify-content:space-between;align-items:center;"><div style="width:49%;text-align:center;"><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/pic17.png" alt="傅立叶级数示意" style="width:100%;border-radius:8px;"><p style="font-size:14px;color:#666;margin-top:8px;">图1：图片来自《心中有数，生活中的数学思维》</p></div><div style="width:49%;text-align:center;"><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/pic18.png" alt="傅立叶级数系数示意" style="width:100%;border-radius:8px;"><p style="font-size:14px;color:#666;margin-top:8px;">图2：图片来自《心中有数，生活中的数学思维》</p></div></div><p>熟悉数据压缩的读者应该知道这个原理，我们只需把少量比较大的系数对应的简单图像和对应的系数一起存起来，就可以恢复原始图像，且大大压缩了存储空间：</p><div style="display:flex;justify-content:space-between;align-items:center;"><div style="width:100%;text-align:center;"><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/growth/pic19.png" alt="数据压缩示意" style="width:100%;border-radius:8px;"><p style="font-size:14px;color:#666;margin-top:8px;">图片来自《心中有数，生活中的数学思维》</p></div></div><p>因此，我们在遇到比较复杂的问题时，不需要害怕，因为现实世界中的事物看似复杂，<strong>一旦转换为其他的表示方法后，通常是稀疏的</strong>。我们只需要<strong>拆解并关注少部分核心要素，以及它们之间的关联即可</strong>。稀疏无处不在，很多看起来复杂的现象背后所包含的规律，往往都是稀疏且简单的。</p><h4 id="概率的世界观" tabindex="-1">概率的世界观 <a class="header-anchor" href="#概率的世界观" aria-label="Permalink to “概率的世界观”">​</a></h4><p>笔者在 2023 年五一假期去『杭州宋城』游玩了一下，快结束时遇到了一个特别有意思的娱乐活动：&quot;赌钱&quot;。这里的 &quot;赌钱&quot;活动是游客拿着在宋城钱庄里兑换的、且消费一天后还剩余的零钱铜板去赌一把，碰碰运气，体验下宋朝的赌场。</p><p>规则很简单：<strong>拿着手里的铜板选择押大或押小，美丽的西子姑娘直接掷骰子，顾客赢了就给同样的下注铜板，庄家赢了就直接赢走下注的铜板</strong>。看似简单又粗暴的规则，一段时间下来，大部分游客基本都把仅剩的铜板留在了宋城，很少有顾客能赢。当然，笔者和朋友也不例外，不过还是采用了一个策略去反抗了下，让游戏时间延长一点：<strong>三个人约定分工，一人只能押大，另一人只能押小，最后一人拿着剩余的铜板自由调度选择押大押小</strong>。可终究没有改变最终的结果，相信熟悉 &quot;大数定律&quot;的人已经知道为什么了：只要一件事情发生的次数足够多，它出现某一个结果的频率就等于其概率。</p><p>宋城这个大庄家是活动举办方，一直有职员在玩，基本可以看成有 1/6 的概率稳赢，广大游客来宋城的目的是游玩，不是『赌钱』，玩得次数相对少太多，赢的概率远远比庄家少。笔者阐述这个『大数定律』的小例子，主要是想引出一些启发，觉得我们需要建立起概率的世界观：</p><ul><li>基础概率是核心，是达成目标的关键因素，<strong>我们的核心是：努力提高自身的基础概率</strong>。</li><li>如果我们<strong>做成某件事的基础概率比较大，重复的次数就是最好的利器，可以去多次重复</strong>；</li><li>如果我们的<strong>基础概率比竞争对手低，需要先看看能不能提高基础概率，若不能提高基础概率，最好的选择是不参与，而是跳到另一个从概率上对自己有利的局里</strong>。</li></ul><h4 id="ai-教会了我们哪些" tabindex="-1">AI 教会了我们哪些？ <a class="header-anchor" href="#ai-教会了我们哪些" aria-label="Permalink to “AI 教会了我们哪些？”">​</a></h4><p>早在几年前，传统的机器学习都是通过『投喂』特定的训练数据给某个单一模型，训练完成后模型能够完成一些特定的任务，但当我们让模型去完成一些别的任务时，其表现就相当差。 我们可以发现，<strong>『单任务学习』看起来是集中精力做一件事，但聚焦于某一特定任务并不是最好的方式，因为特别容易忽略任务之间的关联</strong>。如果我们把不同任务放在一起训练，充分利用任务之间的关系，就很可能让最后训练出来的模型比单独训练出来的模型表现得更好。相信对大模型有一定了解的读者应该已经发现，这跟大语言模型的思路很像，随着训练数据的加大，大语言模型的表现越来越让人惊艳，尤其是自然语言理解方面。</p><p>这也引出了一些好的学习方法论：<strong>通识教育是相当重要的，一个人在学习时所使用的方式、思维模型和章法也是相当重要的</strong>。“技能”通常是针对某个特定的任务而言的，而“学习方法论”则可以应用于多个不同的任务。那些综合表现好的人，一般都掌握了好的学习方法论，借助这些学习方法论，可以经过短时间的学习就能较好地完成多个不同的任务。</p><h2 id="_5-写在最后" tabindex="-1">5. 写在最后 <a class="header-anchor" href="#_5-写在最后" aria-label="Permalink to “5. 写在最后”">​</a></h2><p>行文至此，&quot;疫情后的第一年向外体验&quot; 也基本梳理完成了.在文章的最后，顺便交代下：<strong>这是笔者第一次在文章中大篇幅尝试引入数学相关的知识，鉴于数学功底有限，肯定存在不足之处，有兴趣的可阅读一些更专业的书籍</strong>。</p><p>虽然不少人觉得大模型会成为新的泡沫，笔者这里也不好说看法是否对，但笔者曾阅读过 OpenAI 首席科学家，以及一些研究员早年写的博客，有一个比较共同的特点值得敬佩：<strong>即使有很多人在评论区质疑他们描述的 AGI，但他们大多坚信自己能搞出来通用人工智能，这些年也在用实践推动着 AI 的发展</strong>。</p><p>随着大模型被广泛熟知，AI 应用与变革的路才刚刚开始，希望更多的人能主动思变，拥抱 AI。笔者也会努力继续深入学习 AI，<strong>自从再次深入学习 AI 知识后，作为工作几年后的打工人，有点觉得自己的心态变得年轻、有趣了</strong>。</p>',78)])])}const m=i(o,[["render",e]]);export{d as __pageData,m as default};
